mapper.select:
select count(1)
from cook_ai_messages
where conversation_id = #{conversationId}
  and user_id = #{userId}
  and deleted_at is null
limit 1


where s.deleted_at is null

    and (s.content like concat('%', #{keyword}, '%') or u.nickname like concat('%', #{keyword}, '%'))


    and am.model_type = #{modelType}

group by s.conversation_id, s.user_id, u.nickname, u.avatar_url, s.model_id, am.name, am.model_type

    having flag = #{flag}

order by updated_at desc

mapper.insert:
insert into cook_ai_messages (
    conversation_id, user_id, model_id, role, content, input_tokens, output_tokens,
    response_time_ms, flag, flag_reason, rag_hit, rag_sources_json, fallback_reason
) values (
    #{conversationId}, #{userId}, #{modelId}, #{role}, #{content}, #{inputTokens}, #{outputTokens},
    #{responseTimeMs}, #{flag}, #{flagReason}, #{ragHit}, #{ragSourcesJson}, #{fallbackReason}
)

mapper.update:
update cook_ai_messages
set deleted_at = current_timestamp,
    updated_at = current_timestamp
where conversation_id = #{conversationId}
  and user_id = #{userId}
  and deleted_at is null
